    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

// Custom debounce hook. Returns the debounced value plus a flag that is
// true while a new value is "pending" (i.e. waiting out the delay).
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // A new value came in but hasn't been committed yet.
        setIsPending(true);

        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Clean up on value change AND on unmount to prevent memory leaks.
        return () => {
            clearTimeout(timeoutRef.current);
        };
    }, [value, delay]);

    return [debouncedValue, isPending];
}

// Splits `text` into segments and wraps the first case-insensitive match
// of `query` in a <mark> tag. Treats the query as a literal string (no regex).
function highlightMatch(text, query) {
    if (!query) return text;

    const lowerText = text.toLowerCase();
    const lowerQuery = query.toLowerCase();
    const index = lowerText.indexOf(lowerQuery);

    if (index === -1) return text;

    const before = text.slice(0, index);
    const match = text.slice(index, index + query.length);
    const after = text.slice(index + query.length);

    return (
        <>
            {before}
            <mark>{match}</mark>
            {after}
        </>
    );
}

function ResourceList() {
    const [searchTerm, setSearchTerm] = useState('');
    const [debouncedTerm, isPending] = useDebouncedValue(searchTerm, 300);

    // Treat whitespace-only input as empty.
    const normalizedTerm = debouncedTerm.trim().toLowerCase();

    const filteredItems = useMemo(() => {
        if (!normalizedTerm) return ITEMS;
        // Plain substring match — no regex, so special chars are safe.
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(normalizedTerm)
        );
    }, [normalizedTerm]);

    // Only show the indicator when the user has actually typed something
    // and we're still waiting out the debounce delay.
    const showSearching = isPending && searchTerm.trim() !== '';

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                placeholder="Search resources..."
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                aria-label="Search resources"
            />

            {showSearching && <p aria-live="polite">Searching...</p>}

            {!showSearching && filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, normalizedTerm)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
```

